INSERT INTO discussions (id, course_id, lesson_id, user_id, parent_id, title, content, is_resolved, upvotes, created_at, updated_at) VALUES
('60000000-0000-0000-0000-000000000001', '30000000-0000-0000-0000-000000000001', '40000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000001', NULL, 'Python 安装问题求助', '大家好，我在 Windows 上安装 Python 时遇到了问题。运行 python 命令时提示"不是内部或外部命令"。请问如何解决？已经勾选了"Add Python to PATH"选项。', false, 5, NOW() - INTERVAL '59 days', NOW() - INTERVAL '58 days'),
('60000000-0000-0000-0000-000000000002', '30000000-0000-0000-0000-000000000001', '40000000-0000-0000-0000-000000000003', '20000000-0000-0000-0000-000000000002', NULL, '变量命名有什么最佳实践吗？', '学习变量命名时有些困惑。除了不能用数字开头，还有哪些需要注意的地方？驼峰命名和下划线命名哪个更好？', false, 8, NOW() - INTERVAL '57 days', NOW() - INTERVAL '56 days'),
('60000000-0000-0000-0000-000000000003', '30000000-0000-0000-0000-000000000001', '40000000-0000-0000-0000-000000000005', '20000000-0000-0000-0000-000000000003', NULL, 'for 循环和 while 循环的选择', '什么情况下应该用 for 循环，什么时候用 while 循环？感觉很多时候两者都可以实现。', false, 12, NOW() - INTERVAL '55 days', NOW() - INTERVAL '54 days'),
('60000000-0000-0000-0000-000000000004', '30000000-0000-0000-0000-000000000001', '40000000-0000-0000-0000-000000000006', '20000000-0000-0000-0000-000000000001', NULL, '函数返回值理解', '如果函数没有 return 语句，默认返回什么？为什么有时候打印函数调用结果是 None？', true, 15, NOW() - INTERVAL '53 days', NOW() - INTERVAL '52 days'),
('60000000-0000-0000-0000-000000000005', '30000000-0000-0000-0000-000000000001', '40000000-0000-0000-0000-000000000009', '20000000-0000-0000-0000-000000000002', NULL, '面向对象编程好难啊', '类和对象的概念理解不了太清楚。有没有什么好的例子或者学习方法推荐？感觉比前面的内容难多了。', false, 20, NOW() - INTERVAL '51 days', NOW() - INTERVAL '50 days'),
('60000000-0000-0000-0000-000000000006', '30000000-0000-0000-0000-000000000001', NULL, '10000000-0000-0000-0000-000000000001', NULL, '【课程公告】Python 编程入门学习建议', '同学们好，我是陈教授。学习编程最重要的是多动手练习。建议每学完一章就完成对应的练习题，遇到问题欢迎在讨论区提问。祝大家学习顺利！', true, 50, NOW() - INTERVAL '60 days', NOW() - INTERVAL '30 days');
INSERT INTO discussions (id, course_id, lesson_id, user_id, parent_id, title, content, is_resolved, upvotes, created_at, updated_at) VALUES
('60000000-0000-0000-0000-000000000007', '30000000-0000-0000-0000-000000000001', '40000000-0000-0000-0000-000000000002', '20000000-0000-0000-0000-000000000002', '60000000-0000-0000-0000-000000000001', NULL, '试试重新安装，一定要勾选 Add to PATH', '我之前也遇到这个问题，后来重新安装时仔细勾选了"Add Python to PATH"，安装完成后重启电脑就好了。如果还不行，可以手动添加环境变量。', false, 3, NOW() - INTERVAL '58 days', NOW() - INTERVAL '58 days'),
('60000000-0000-0000-0000-000000000008', '30000000-0000-0000-0000-000000000001', '40000000-0000-0000-0000-000000000002', '10000000-0000-0000-0000-000000000001', '60000000-0000-0000-0000-000000000001', NULL, NULL, '官方解答：请检查环境变量配置。可以在系统属性 - 高级 - 环境变量中，将 Python 安装路径添加到 Path 变量中。', true, 10, NOW() - INTERVAL '58 days', NOW() - INTERVAL '58 days');
INSERT INTO discussions (id, course_id, lesson_id, user_id, parent_id, title, content, is_resolved, upvotes, created_at, updated_at) VALUES
('60000000-0000-0000-0000-000000000011', '30000000-0000-0000-0000-000000000002', '40000000-0000-0000-0000-00000000000c', '20000000-0000-0000-0000-000000000001', NULL, 'NumPy 和 Pandas 的区别', '刚学完数据科学库这章，想请教一下 NumPy 和 Pandas 各自的使用场景是什么？什么时候用 NumPy，什么时候用 Pandas？', false, 18, NOW() - INTERVAL '53 days', NOW() - INTERVAL '52 days'),
('60000000-0000-0000-0000-000000000012', '30000000-0000-0000-0000-000000000002', '40000000-0000-0000-0000-00000000000d', '20000000-0000-0000-0000-000000000002', NULL, '特征缩放必须做吗？', '数据预处理中的特征缩放，是不是所有情况下都需要做？如果特征的取值范围本来就很接近，可以不做缩放吗？', false, 14, NOW() - INTERVAL '51 days', NOW() - INTERVAL '50 days'),
('60000000-0000-0000-0000-000000000013', '30000000-0000-0000-0000-000000000002', '40000000-0000-0000-0000-00000000000e', '20000000-0000-0000-0000-000000000003', NULL, '线性回归的假设条件', '线性回归有哪些基本假设？如果数据不满足这些假设怎么办？', true, 22, NOW() - INTERVAL '49 days', NOW() - INTERVAL '48 days'),
('60000000-0000-0000-0000-000000000014', '30000000-0000-0000-0000-000000000002', '40000000-0000-0000-0000-000000000010', '20000000-0000-0000-0000-000000000001', NULL, '随机森林的随机性体现在哪里？', '随机森林为什么叫"随机"森林？随机性具体体现在什么地方？和普通的决策树有什么区别？', false, 25, NOW() - INTERVAL '47 days', NOW() - INTERVAL '46 days'),
('60000000-0000-0000-0000-000000000015', '30000000-0000-0000-0000-000000000002', '40000000-0000-0000-0000-000000000013', '20000000-0000-0000-0000-000000000002', NULL, '过拟合问题怎么解决？', '我的模型在训练集上表现很好，但在测试集上效果很差，应该是过拟合了。有哪些方法可以缓解过拟合？', true, 30, NOW() - INTERVAL '45 days', NOW() - INTERVAL '44 days'),
('60000000-0000-0000-0000-000000000016', '30000000-0000-0000-0000-000000000002', NULL, '10000000-0000-0000-0000-000000000001', NULL, '【学习资源】机器学习数学基础推荐', '有同学问机器学习的数学基础。建议先掌握：线性代数（矩阵运算、特征值）、微积分（导数、梯度）、概率统计（分布、贝叶斯）。推荐 3Blue1Brown 的视频教程。', true, 45, NOW() - INTERVAL '54 days', NOW() - INTERVAL '40 days');
INSERT INTO discussions (id, course_id, lesson_id, user_id, parent_id, title, content, is_resolved, upvotes, created_at, updated_at) VALUES
('60000000-0000-0000-0000-000000000021', '30000000-0000-0000-0000-000000000003', '40000000-0000-0000-0000-000000000017', '20000000-0000-0000-0000-000000000001', NULL, 'CSS Flexbox 布局困惑', 'Flexbox 的 justify-content 和 align-items 总是搞混。有没有什么记忆技巧或者可视化工具推荐？', false, 16, NOW() - INTERVAL '47 days', NOW() - INTERVAL '46 days'),
('60000000-0000-0000-0000-000000000022', '30000000-0000-0000-0000-000000000003', '40000000-0000-0000-0000-000000000018', '20000000-0000-0000-0000-000000000002', NULL, 'JavaScript 闭包理解不了', '闭包的概念看了好几遍还是不太明白。能不能用更通俗的例子解释一下？闭包在实际开发中有什么应用场景？', true, 28, NOW() - INTERVAL '45 days', NOW() - INTERVAL '44 days'),
('60000000-0000-0000-0000-000000000023', '30000000-0000-0000-0000-000000000003', '40000000-0000-0000-0000-00000000001a', '20000000-0000-0000-0000-000000000003', NULL, 'Node.js 版本选择', 'Node.js 有多个 LTS 版本，应该选择哪个版本学习？v18 还是 v20？不同版本之间差异大吗？', false, 10, NOW() - INTERVAL '43 days', NOW() - INTERVAL '42 days'),
('60000000-0000-0000-0000-000000000024', '30000000-0000-0000-0000-000000000003', '40000000-0000-0000-0000-00000000001c', '20000000-0000-0000-0000-000000000001', NULL, 'JWT Token 安全性问题', 'JWT Token 存储在客户端安全吗？如果被盗用了怎么办？需要实现 Token 刷新机制吗？', true, 35, NOW() - INTERVAL '41 days', NOW() - INTERVAL '40 days'),
('60000000-0000-0000-0000-000000000025', '30000000-0000-0000-0000-000000000003', '40000000-0000-0000-0000-00000000001e', '20000000-0000-0000-0000-000000000002', NULL, '博客系统项目部署问题', '按照教程部署博客系统时，在云服务器上遇到了跨域问题。本地开发没问题，部署后前端无法访问后端 API，怎么解决？', false, 20, NOW() - INTERVAL '39 days', NOW() - INTERVAL '38 days'),
('60000000-0000-0000-0000-000000000026', '30000000-0000-0000-0000-000000000003', NULL, '10000000-0000-0000-0000-000000000002', NULL, '【项目展示】优秀博客系统作品', '恭喜以下同学完成了博客系统项目：student_zhao, student_wu, student_zhou。你们的作品已经展示在项目墙，欢迎大家参观学习！', true, 40, NOW() - INTERVAL '40 days', NOW() - INTERVAL '35 days');
INSERT INTO discussions (id, course_id, lesson_id, user_id, parent_id, title, content, is_resolved, upvotes, created_at, updated_at) VALUES
('60000000-0000-0000-0000-000000000031', '30000000-0000-0000-0000-000000000004', '40000000-0000-0000-0000-00000000001f', '20000000-0000-0000-0000-000000000001', NULL, '时间复杂度计算疑问', '嵌套循环一定是 O(n²) 吗？如果内层循环的次数和外层有关，应该怎么计算？', true, 24, NOW() - INTERVAL '43 days', NOW() - INTERVAL '42 days'),
('60000000-0000-0000-0000-000000000032', '30000000-0000-0000-0000-000000000004', '40000000-0000-0000-0000-000000000021', '20000000-0000-0000-0000-000000000002', NULL, '链表 vs 数组的选择', '实际开发中，什么时候应该用链表，什么时候用数组？感觉数组用得更多，那学习链表的意义是什么？', false, 32, NOW() - INTERVAL '41 days', NOW() - INTERVAL '40 days'),
('60000000-0000-0000-0000-000000000033', '30000000-0000-0000-0000-000000000004', '40000000-0000-0000-0000-000000000023', '20000000-0000-0000-0000-000000000003', NULL, '哈希表负载因子', '哈希表的负载因子 (load factor) 是什么？为什么达到一定阈值需要扩容？扩容的代价大吗？', false, 18, NOW() - INTERVAL '39 days', NOW() - INTERVAL '38 days'),
('60000000-0000-0000-0000-000000000034', '30000000-0000-0000-0000-000000000004', '40000000-0000-0000-0000-000000000024', '20000000-0000-0000-0000-000000000001', NULL, '二叉树遍历的递归和非递归实现', '二叉树遍历用递归很简单，但面试常考非递归实现。有没有什么记忆技巧或者模板？', true, 40, NOW() - INTERVAL '37 days', NOW() - INTERVAL '36 days'),
('60000000-0000-0000-0000-000000000035', '30000000-0000-0000-0000-000000000004', '40000000-0000-0000-0000-000000000028', '20000000-0000-0000-0000-000000000002', NULL, '动态规划太难了', '动态规划的题目完全找不到思路。怎么判断一道题是否适合用动态规划？状态转移方程怎么推导？', false, 45, NOW() - INTERVAL '35 days', NOW() - INTERVAL '34 days'),
('60000000-0000-0000-0000-000000000036', '30000000-0000-0000-0000-000000000004', NULL, '10000000-0000-0000-0000-000000000003', NULL, '【刷题建议】算法学习路径', '学习算法建议按以下顺序：1.数组/字符串 2.链表 3.栈/队列 4.哈希表 5.树 6.图 7.排序 8.动态规划。每个专题至少刷 20 道题。推荐 LeetCode 和 力扣中国。', true, 60, NOW() - INTERVAL '44 days', NOW() - INTERVAL '30 days');
INSERT INTO discussions (id, course_id, lesson_id, user_id, parent_id, title, content, is_resolved, upvotes, created_at, updated_at) VALUES
('60000000-0000-0000-0000-000000000041', '30000000-0000-0000-0000-000000000005', '40000000-0000-0000-0000-00000000002a', '20000000-0000-0000-0000-000000000001', NULL, '神经网络层数选择', '神经网络应该建多深？层数越多效果一定越好吗？有没有什么经验法则？', false, 22, NOW() - INTERVAL '37 days', NOW() - INTERVAL '36 days'),
('60000000-0000-0000-0000-000000000042', '30000000-0000-0000-0000-000000000005', '40000000-0000-0000-0000-00000000002b', '20000000-0000-0000-0000-000000000002', NULL, 'TensorFlow 和 PyTorch 选哪个？', '两个框架都在学，但感觉精力不够。业界现在更倾向于用哪个？找工作哪个更吃香？', true, 38, NOW() - INTERVAL '35 days', NOW() - INTERVAL '34 days'),
('60000000-0000-0000-0000-000000000043', '30000000-0000-0000-0000-000000000005', '40000000-0000-0000-0000-00000000002d', '20000000-0000-0000-0000-000000000003', NULL, 'CNN 参数计算问题', '卷积层的参数数量怎么计算？卷积核大小、通道数、步长这些参数对输出有什么影响？', false, 26, NOW() - INTERVAL '33 days', NOW() - INTERVAL '32 days'),
('60000000-0000-0000-0000-000000000044', '30000000-0000-0000-0000-000000000005', '40000000-0000-0000-0000-00000000002e', '20000000-0000-0000-0000-000000000001', NULL, 'LSTM 的遗忘门理解', 'LSTM 的三个门（遗忘门、输入门、输出门）各自的作用是什么？能不能用通俗的例子解释？', true, 35, NOW() - INTERVAL '31 days', NOW() - INTERVAL '30 days'),
('60000000-0000-0000-0000-000000000045', '30000000-0000-0000-0000-000000000005', '40000000-0000-0000-0000-000000000030', '20000000-0000-0000-0000-000000000002', NULL, 'GAN 训练不稳定怎么办？', '按照教程实现 GAN，但生成器总是崩溃，判别器很快就能区分真假。调整学习率也没什么用，有什么训练技巧吗？', false, 28, NOW() - INTERVAL '29 days', NOW() - INTERVAL '28 days'),
('60000000-0000-0000-0000-000000000046', '30000000-0000-0000-0000-000000000005', '40000000-0000-0000-0000-000000000031', '20000000-0000-0000-0000-000000000003', NULL, '模型部署到生产环境', '训练好的模型怎么部署到生产环境？需要考虑哪些问题？有推荐的部署方案吗？', false, 30, NOW() - INTERVAL '27 days', NOW() - INTERVAL '26 days'),
('60000000-0000-0000-0000-000000000047', '30000000-0000-0000-0000-000000000005', NULL, '10000000-0000-0000-0000-000000000003', NULL, '【前沿技术】深度学习最新进展', '推荐大家关注以下方向：Transformer 架构、大语言模型 (LLM)、扩散模型 (Diffusion)、多模态学习。这些是当前最热门的研究方向。', true, 55, NOW() - INTERVAL '38 days', NOW() - INTERVAL '25 days');
